@(IsMandatory=true, IsFabricName=true, DisplayName="Fabric Name", Description="Please provide the fabric name to create it (Max Size 64)")
string FABRIC_NAME{
  minLength = 1;
  maxLength = 64;
};

@(IsMandatory=true, IsL2VniRange=true, Description="Overlay Network Identifier Range (Min:1, Max:16777214)", DisplayName="Layer 2 VXLAN VNI Range")
integerRange L2_SEGMENT_ID_RANGE
{
min=1;
max=16777214;
defaultValue=30000-49000;
};

@(IsMandatory=true, IsL3VniRange=true, Description="Overlay VRF Identifier Range (Min:1, Max:16777214)", DisplayName="Layer 3 VXLAN VNI Range")
integerRange L3_PARTITION_ID_RANGE
{
min=1;
max=16777214;
defaultValue=50000-59000;
};


@(IsMandatory=true, IsVrfTemplate=true, Enum="%TEMPLATES.vrf", Description="Default Overlay VRF Template For Leafs", DisplayName="VRF Template", AlwaysSetDefault=true)
string default_vrf
{
defaultValue=Default_VRF_Universal;
};

@(IsMandatory=true, IsNetworkTemplate=true, Enum="%TEMPLATES.network", Description="Default Overlay Network Template For Leafs", DisplayName="Network Template", AlwaysSetDefault=true)
string default_network
{
defaultValue=Default_Network_Universal;
};

@(IsMandatory=true, IsVrfExtensionTemplate=true, Enum="%TEMPLATES.vrfExtension", Description="Default Overlay VRF Template For Borders", DisplayName="VRF Extension Template", AlwaysSetDefault=true)
string vrf_extension_template
{
defaultValue=Default_VRF_Extension_Universal;
};

@(IsMandatory=true, IsNetworkExtensionTemplate=true, Enum="%TEMPLATES.networkExtension", Description="Default Overlay Network Template For Borders", DisplayName="Network Extension Template", AlwaysSetDefault=true)
string network_extension_template
{
defaultValue=Default_Network_Extension_Universal;
};

@(IsMandatory=false, DisplayName="Enable Private VLAN (PVLAN)", Description="Enable PVLAN on MSD and its child fabrics")
boolean ENABLE_PVLAN {
defaultValue=false;
};

@(IsMandatory=false, IsInternal=true)
boolean ENABLE_PVLAN_PREV;

@(IsMandatory="ENABLE_PVLAN==true", IsShow="ENABLE_PVLAN==true", IsPvlanSecNetworkTemplate=true, IsPvlanSecNetworkExtTemplate=true, Enum="%TEMPLATES.pvlanSecNetwork", Description="Default PVLAN Secondary Network Template", DisplayName="PVLAN Secondary Network Template", AlwaysSetDefault=true)
string default_pvlan_sec_network
{
defaultValue=Pvlan_Secondary_Network;
};

@(IsMandatory=false, IsAnycastGatewayMac=true, Description="Shared MAC address for all leaves", DisplayName="Anycast-Gateway-MAC")
string ANYCAST_GW_MAC
{
defaultValue=2020.0000.00aa;
};

@(IsMandatory=true, IsFabricType=true, DisplayName="Fabric Type", ReadOnly=true, Section="Hidden")
string FABRIC_TYPE
{
defaultValue=MFD;
};

@(IsMandatory=false, Section="Hidden")
string EXT_FABRIC_TYPE;

@(IsMandatory=true, DisplayName="Template Family", Section="Hidden")
string FF
{
defaultValue=MSD;
};

@(IsMandatory=false, IsInternal=true)
string MSO_CONTROLER_ID;
@(IsMandatory=false, IsInternal=true)
string MSO_SITE_GROUP_NAME;
@(IsMandatory=false, IsInternal=true)
string PREMSO_PARENT_FABRIC;
@(IsMandatory=false, IsInternal=true)
string DCNM_ID;

@(IsMandatory=true, Enum="Manual,Centralized_To_Route_Server,Direct_To_BGWS",
Description="Manual, <br/>Auto Overlay EVPN Peering to Route Servers, <br/>Auto Overlay EVPN Direct Peering to Border Gateways",
DisplayName="Multi-Site Overlay IFC <br/>Deployment Method", Section="DCI")
string BORDER_GWY_CONNECTIONS
{
defaultValue=Manual;
};
@(IsMandatory="BORDER_GWY_CONNECTIONS==Centralized_To_Route_Server", IsShow="BORDER_GWY_CONNECTIONS==Centralized_To_Route_Server",  Description="Multi-Site Route-Server peer list (typically loopback IP address on Route-Server for Multi-Site EVPN peering with BGWs), e.g. 128.89.0.1, 128.89.0.2", DisplayName="Multi-Site Route Server List", Section="DCI")
ipAddressList RP_SERVER_IP;

@(IsMandatory="BORDER_GWY_CONNECTIONS==Centralized_To_Route_Server", IsShow="BORDER_GWY_CONNECTIONS==Centralized_To_Route_Server",  Description="1-4294967295 | 1-65535[.0-65535], e.g. 65000, 65001", DisplayName="Multi-Site Route Server <br/>BGP ASN List", Section="DCI")
string BGP_RP_ASN;

@(IsMandatory=false, IsShow="BORDER_GWY_CONNECTIONS==Centralized_To_Route_Server", DisplayName="Enable 'redistribute direct' on Route Servers", Description="For auto-created Multi-Site overlay IFCs in Route Servers. Applicable only when Multi-Site Overlay IFC Deployment Method is Centralized_To_Route_Server.", Section="DCI")
boolean ENABLE_RS_REDIST_DIRECT {
defaultValue=false;
};

@(IsMandatory=false, IsShow="ENABLE_RS_REDIST_DIRECT==true", DisplayName="Route Server IP TAG", Description="Routing tag associated with Route Server IP for redistribute direct. This is the IP used in eBGP EVPN peering.", Section="DCI")
string RS_ROUTING_TAG {
   defaultValue=54321;
};

@(IsMandatory=false, DisplayName="Multi-Site Underlay IFC <br/>Auto Deployment Flag", Section="DCI")
boolean MS_UNDERLAY_AUTOCONFIG
{
defaultValue=false;
};

@(IsMandatory=false, IsShow="MS_UNDERLAY_AUTOCONFIG==true", DisplayName="BGP Send-community on Multi-Site Underlay IFC", Description="For auto-created Multi-Site Underlay IFCs", Section="DCI")
boolean ENABLE_BGP_SEND_COMM {
defaultValue=false;
};

@(IsMandatory=false, IsShow="MS_UNDERLAY_AUTOCONFIG==true", DisplayName="BGP log neighbor change on Multi-Site Underlay IFC", Description="For auto-created Multi-Site Underlay IFCs", Section="DCI")
boolean ENABLE_BGP_LOG_NEIGHBOR_CHANGE {
defaultValue=false;
};

@(IsMandatory=false, IsShow="MS_UNDERLAY_AUTOCONFIG==true", DisplayName="BGP BFD on Multi-Site Underlay IFC", Description="For auto-created Multi-Site Underlay IFCs", Section="DCI")
boolean ENABLE_BGP_BFD {
defaultValue=false;
};

@(IsMandatory=false, DisplayName="Delay Restore time", Description="Multi-Site underlay and overlay control plane <br/> convergence time (Min:30, Max:1000) in seconds ", Section="DCI")
integer DELAY_RESTORE {
min = 30;
max = 1000;
defaultValue=300;
};

@(IsMandatory=false, DisplayName="Multi-Site CloudSec", Description="Auto Config CloudSec on Border Gateways", Section="DCI")
boolean CLOUDSEC_AUTOCONFIG {
defaultValue=false;
};

@(IsMandatory=true, IsShow="CLOUDSEC_AUTOCONFIG==true", DisplayName="CloudSec Key String", Description="Cisco Type 7 Encrypted Octet String", Section="DCI")
string CLOUDSEC_KEY_STRING {
minLength = 1;
maxLength = 130;
regularExpr=^[a-fA-F0-9]+$;
};

@(IsMandatory=true, IsShow="CLOUDSEC_AUTOCONFIG==true", DisplayName="CloudSec Cryptographic Algorithm", Description="AES_128_CMAC or AES_256_CMAC", Section="DCI")
enum CLOUDSEC_ALGORITHM {
validValues=AES_128_CMAC,AES_256_CMAC;
defaultValue=AES_128_CMAC;
};

@(IsMandatory=true, IsShow="CLOUDSEC_AUTOCONFIG==true", DisplayName="CloudSec Enforcement", Description="If set to 'strict', data across site must be encrypted.", Section="DCI")
enum CLOUDSEC_ENFORCEMENT {
validValues=strict,loose;
};

@(IsMandatory=true, IsShow="CLOUDSEC_AUTOCONFIG==true", DisplayName="CloudSec Status Report Timer", Description="CloudSec Operational Status periodic report timer in minutes", Section="DCI")
integer CLOUDSEC_REPORT_TIMER {
min = 5;
max = 60;
defaultValue=5;
};

@(IsMandatory=false, DisplayName="Enable Multi-Site eBGP Password", Description="eBGP password for Multi-Site underlay/overlay IFCs", Section="DCI")
boolean MS_IFC_BGP_PASSWORD_ENABLE {
defaultValue=false;
};

@(IsMandatory=true, IsShow="MS_IFC_BGP_PASSWORD_ENABLE==true", DisplayName="eBGP Password", Description="Encrypted eBGP Password Hex String", Section="DCI")
string MS_IFC_BGP_PASSWORD {
minLength = 1;
maxLength = 130;
regularExpr=^[a-fA-F0-9]+$;
};

@(IsMandatory=true, Enum="3,7", IsShow="MS_IFC_BGP_PASSWORD_ENABLE==true", DisplayName="eBGP Authentication Key <br/>Encryption Type", Description="BGP Key Encryption Type: 3 - 3DES, 7 - Cisco", Section="DCI")
string MS_IFC_BGP_AUTH_KEY_TYPE {
defaultValue=3;
};

@(IsMandatory=false, IsInternal=true)
boolean MS_IFC_BGP_PASSWORD_ENABLE_PREV;
@(IsMandatory=false, IsInternal=true)
string MS_IFC_BGP_AUTH_KEY_TYPE_PREV;
@(IsMandatory=false, IsInternal=true)
string MS_IFC_BGP_PASSWORD_PREV;

@(IsMandatory=true, Description="(Min:0, Max:1023)", DisplayName="Multi-Site VTEP VIP Loopback Id")
integer MS_LOOPBACK_ID{
min=0;
max=1023;
defaultValue=100;
};

@(IsMandatory=false, DisplayName="Border Gateway IP TAG", Description="Routing tag associated with IP address of loopback and DCI interfaces")
string BGW_ROUTING_TAG {
   defaultValue=54321;
};

@(IsMandatory=false, DisplayName="BGW IP TAG", Section="Hidden")
string BGW_ROUTING_TAG_PREV {
   defaultValue=54321;
};

@(IsMandatory=false, Description="Enables Overlay VLANs on uplink between ToRs and Leafs", DisplayName="ToR Auto-deploy Flag")
boolean TOR_AUTO_DEPLOY{
defaultValue=false;
};

@(IsMandatory=true,  Description="Typically Loopback100 IP Address Range", DisplayName="Multi-Site VTEP VIP Loopback IP <br/>Range", Section="Resources")
ipV4AddressWithSubnet LOOPBACK100_IP_RANGE
{
defaultValue=10.10.0.0/24;
};

@(IsMandatory=true, Description="Address range to assign P2P DCI Links", DisplayName="DCI Subnet IP Range", Section="Resources")
ipV4AddressWithSubnet DCI_SUBNET_RANGE
{
defaultValue=10.10.1.0/24;
};

@(IsMandatory=true, Description="Target Mask for Subnet Range (Min:8, Max:31)", DisplayName="Subnet Target Mask", Section="Resources")
integer DCI_SUBNET_TARGET_MASK
{
min = 8;
max = 31;
defaultValue=30;
};

#Configuration Backup settings
@(IsMandatory=false, NoConfigChg=true, Description="Backup at the specified time. Note: Fabric Backup/Restore functionality is being deprecated for MSD fabrics. Recommendation is to use NDFC Backup & Restore", DisplayName="Scheduled Fabric Backup", Section="Configuration Backup")
boolean enableScheduledBackup;
@(IsMandatory=true, NoConfigChg=true, IsShow="enableScheduledBackup==true",Description="Time (UTC) in 24hr format. (00:00 to 23:59)", DisplayName="Scheduled Time", Section="Configuration Backup")
string scheduledTime
{
    regularExpr=^([01]\d|2[0-3]):([0-5]\d)$;

};

