from com.cisco.dcbu.vinci.rest.services.jython import PTIWrapper as PTI
from com.cisco.dcbu.vinci.rest.services.jython import ResourceManagerWrapper
from com.cisco.dcbu.vinci.rest.services.jython import Wrapper
from com.cisco.dcbu.vinci.rest.services.jython import WrappersResp
from com.cisco.dcbu.vinci.rest.services.jython import MfdWrapper
from com.cisco.dcbu.vinci.rest.services.jython import MfdResp
from com.cisco.dcbu.vinci.rest.services.jython import Helper
from com.cisco.dcbu.vinci.rest.services.jython import TopologyWrapper
from com.cisco.dcbu.vinci.rest.services.jython import ResourceManagerWrapper as RM
from com.cisco.dcbu.vinci.rest.services.jython import ReportWrapper
from com.cisco.dcbu.vinci.rest.services.jython import VpcWrapper
from com.cisco.dcbu.vinci.rest.services.jython import InterfabricConnectionWrapper as IFC
from com.cisco.dcbu.pti.resource import CtrlPolicySearch
from com.cisco.dcbu.vinci.rest.services.jython import FabricWrapper
from com.cisco.dcbu.vinci.rest.services.jython import BackupRestoreWrapper as BRW

from utility import *
from topology import *
import inspect
import sys, traceback
import copy

def capabilities(dictonaryObj):
    Wrapper.print("==========capabilities==========")
    Wrapper.print("Fabric Name = %s" % FABRIC_NAME)
    Wrapper.print("Number of keys = %d" % len(dictonaryObj))
    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()
    respObj.setValue(['fabricInit', 'preFabricDelete', 'fabricDelete', 'preAdd', 'postAdd'])
    return respObj

def isFabricMSOSiteGroup(fabricName):
    isMSOSiteGroup = False
    fabDetails = Util.exe(FabricWrapper.get(fabricName))
    fabTech = fabDetails.getFabricTechnology()
    if fabTech == "MSOSiteGroup":
        isMSOSiteGroup = True
    return isMSOSiteGroup

def compareParamValue(param, nw, nw2, nwId, paramNames, errList):
    paramVal1 = nw.get(param, None)
    paramVal2 = nw2.get(param, None)

    if paramVal1 != None and paramVal2 != None and paramVal1 != paramVal2:
        Wrapper.print("Checking NW ID: [%d] : Param [%s]: [%s] != [%s]" % (nwId, param, paramVal1, paramVal2))
        paramDesc = paramNames[param]
        errList.append("%s mismatch [%s], [%s]" % (paramDesc, paramVal1, paramVal2))

# This function is shared by all network types (PVLAN and non PVLAN Networks), under the assumption
# that in PVLAN Secondary Network, parameters not applicable (like mtu) are not present
def compareTemplateConfig(nw, nw2, nwId, fabric1, fabric2):
   funcName = sys._getframe(0).f_code.co_name

   errList = []
   Wrapper.print("%s: NW ID: [%d] fabric1 [%s] fabric2 [%s]" % (funcName, nwId, fabric1, fabric2))
   Wrapper.print("%s: Nw1: %s" % (funcName, nw))
   Wrapper.print("%s: Nw2: %s" % (funcName, nw2))
   try:
      paramNames = {"isLayer2Only" : "Layer 2 Only"}
      for param in paramNames:
          compareParamValue(param, nw, nw2, nwId, paramNames, errList)

      if len(errList) == 0:
          # Not comparing mcast subnet as its fabric instance
          #not comparing vlan as thats of local significance
          l3ParamNames = {"gatewayIpAddress" : "IPv4 Gateway/NetMask",
                        "gatewayIpV6Address" : "IPv6 Gateway/Prefix",
                        "mtu" : "MTU for L3 interface",
                        "suppressArp" : "ARP Suppression",
                        "secondaryGW1" : "IPv4 Secondary GW1",
                        "secondaryGW2" : "IPv4 Secondary GW2",
                        "secondaryGW3" : "IPv4 Secondary GW3",
                        "secondaryGW4" : "IPv4 Secondary GW4",
                        "vlanName" : "VLAN Name",
                        "rtBothAuto" : "L2 VNI Route-Target Both Enable",
                        "intfDescription" : "Interface Description",
                        "tag": "Routing Tag"
                        }
          for param in l3ParamNames:
            compareParamValue(param, nw, nw2, nwId, l3ParamNames, errList)

   except Exception as e:
      msg = ("%s: Exception %s" % (funcName, repr(e)))
      Wrapper.print(msg)
      errList.append(msg)
   finally:
      status = True
      if len(errList):
         status = False
      Wrapper.print("%s: Status = [%r] NW Template Config Error Count [%d]" % (funcName, status, len(errList)))
      return errList, status

#Check if vrf1 name exists in list of vrfs for fabric 2
def vrfCompareName(vrf1, vrf2List, fabric1, fabric2, respObj):
   funcName = sys._getframe(0).f_code.co_name
   try:
      if "vrfName" in vrf1:
         vrfName = vrf1["vrfName"]
         for vrf2 in vrf2List:
            if "vrfName" in vrf2:
               if vrfName == vrf2["vrfName"]:
                  Wrapper.print("vrfName Error for: " + vrfName + "is same: " )
                  if "vrfId" in vrf1 and "vrfId" in vrf2:
                     Wrapper.print("for different VRF ID: " + str(vrf1["vrfId"]) + 
                                   str(vrf2["vrfId"]))
                     respObj.setFailureRetCode()
                     respObj.addErrorReport(funcName, 
                            ("VRF [%s] name error - associated with VNI [%d] in fabric [%s] and VNI [%d] in fabric [%s] " % (vrfName,
                              vrf1["vrfId"], fabric1, vrf2["vrfId"], fabric2)))
                  else:
                     Wrapper.print("Duplicate vrfName Error for: " + vrfName)
                     respObj.setFailureRetCode()
                     respObj.addErrorReport(funcName, "Duplicate VRF Name error for VRF name. diff Id: " + vrfName)
                  return False

   except Exception as e:
      msg = ("Exception %s" % (traceback.format_exc()))
      respObj.setFailureRetCode()
      respObj.addErrorReport(funcName, msg)
      Wrapper.print("%s: %s" % (funcName, msg));
      return False

   return True

#Check if nw1 name exists in list of nws for fabric 2
def nwCompareName(nw1, nw2List, fabric1, fabric2, respObj):
    funcName = sys._getframe(0).f_code.co_name
    try:
      if "nwName" in nw1:
         nwName = nw1["nwName"]
         for nw2 in nw2List:
            if "nwName" in nw2:
               if nwName == nw2["nwName"]:
                  Wrapper.print("nwName Error for: " + nwName + "is same: " )
                  if "nwId" in nw1 and "nwId" in nw2:
                     Wrapper.print("for different NW ID: " + str(nw1["nwId"]) + 
                                   str(nw2["nwId"]))
                     respObj.setFailureRetCode()
                     respObj.addErrorReport(funcName, 
                            ("Network [%s] name error - associated with VNI [%d] in fabric [%s] and VNI [%d] in fabric [%s] " % (nwName,
                              nw1["nwId"], fabric1, nw2["nwId"], fabric2)))
                  else:
                     Wrapper.print("Duplicate nwName Error for: " + nwName)
                     respObj.setFailureRetCode()
                     respObj.addErrorReport(funcName, "Duplicate NW Name error for NW name. diff Id: " + nwName)
                  return False

    except Exception as e:
      msg = ("Exception %s" % (traceback.format_exc()))
      respObj.setFailureRetCode()
      respObj.addErrorReport(funcName, msg)
      Wrapper.print("%s: %s" % (funcName, msg));
      return False

    return True

#Utility functions for pre add Check
def nwCompareFields(nw, nw2, fabric1, fabric2):
    funcName = sys._getframe(0).f_code.co_name

    errList = []
    Wrapper.print("%s: VNI [%s] Nw [%s] Nw2 [%s]" % (funcName, nw["nwId"], nw, nw2))

    try:
        # the nwType value returned from backend is of type LanNetworkTypeEnum
        nwType1 = str(nw.get("nwType", "Normal"))
        nwType2 = str(nw2.get("nwType", "Normal"))

        if nwType1 != nwType2:
            errList.append("VNI %s Network Type mismatch: network %s in fabric %s is type %s, %s in fabric %s is type %s " %
                           (nw["nwId"], nw["nwName"], fabric1, nwType1, nw2["nwName"], fabric2, nwType2))
        else:
            if nwType1 == "Normal" or nwType1 == "Primary":
                params = {
                          "nwName" : "NW Name",
                          "nwTemplate" : "NW Template",
                          "nwExtensionTemplate": "NW Extension Template",
                          "vrfName" : "NW VRF Name"
                         }
            else:
                # PVLAN Network
                params = {
                          "nwName" : "NW Name",
                          "nwTemplate" : "NW Template",
                          "nwPrimaryNetworkName": "PVLAN Primary Network Name"
                         }
            for param in params:
                val1 = nw.get(param, None)
                val2 = nw2.get(param, None)

                Wrapper.print("%s: VNI [%s] Param [%s] val1 [%s] val2 [%s]" % (funcName, nw["nwId"], param, val1, val2))
                if val1 == None:
                    errList.append("%s is not present in network entry for fabric [%s]" % (params[param], fabric1))
                elif val2 == None:
                    errList.append("%s is not present in network entry for fabric [%s]" % (params[param], fabric2))
                elif val1 != val2:
                    errList.append("%s mismatch - [%s], [%s]" % (params[param], val1, val2))

            if "nwTemplateParams" in nw and "nwTemplateParams" in nw2:
                errorNwConfigList, checkPassed = compareTemplateConfig(nw["nwTemplateParams"],
                                                               nw2["nwTemplateParams"], nw["nwId"], fabric1, fabric2)
                if checkPassed == False:
                  errList.extend(errorNwConfigList)
    except Exception as e:
        msg = ("%s: Exception %s" % (funcName, traceback.format_exc()))
        Wrapper.print(msg)
        errList.append(msg)
    finally:
        status = True
        if len(errList):
          status = False
        Wrapper.print("%s: Status = [%r] NW Match Error Count [%d]" % (funcName, status, len(errList)))
        return errList, status

def buildNetworkDict(fabName, nwList):
    netDict = {}

    for entry in nwList:
        nwType = str(entry.get("nwType", "Normal"))
        if nwType != "Normal" and nwType != "Primary":
            # PVLAN Secondary network
            continue

        netCfg = entry["nwTemplateParams"]

        isL2 = False

        vrfName = entry["vrfName"]
        # check if the network is L3 (vrf name is valid)
        if vrfName == "NA":
            # most probably l2, but, double check by looking at 'isLayer2Only' and assume it is L2 if key is not present
            isL2 = netCfg.get("isLayer2Only", "true")
            if isL2 == "true":
                isL2 = True

        #Wrapper.print("buildNetworkDict: Fab [%s] NW [%d/%s] VRF [%s] isL2 [%r]" % (fabName,
        #                            entry["nwId"], entry["nwName"], entry["vrfName"], isL2));
        if isL2:
            continue

        if vrfName not in netDict:
            # add a new VRF entry
            netDict[vrfName] = {}

        vrfEntry = netDict[vrfName]

        if entry["nwId"] not in vrfEntry:
            # add a new Network Entry with the 
            vrfEntry[entry["nwId"]] = entry

    #Wrapper.print("buildNetworkDict: Fab [%s] netDict %s" % (fabName, netDict))
    return netDict

def checkGwIPUniqueness(msdfab, msdNwList, memberFabName, memberNwList, respObj):
    funcName = sys._getframe(0).f_code.co_name
    msdNetDict = buildNetworkDict(msdfab, msdNwList)
    memberNetDict = buildNetworkDict(memberFabName, memberNwList)

    hasError = False
    # make sure the new member network GW IPs are unique
    for vrfName in memberNetDict:
        if vrfName not in msdNetDict:
            # nothing to check
            continue

        msdVrfEntry = msdNetDict[vrfName]
        memberVrfEntry = memberNetDict[vrfName]

        for netId in memberVrfEntry:
            if netId in msdVrfEntry:
                # no need to check further since the GW IP address checks must have occured already
                continue

            # check to make sure the v4/v6 GW IP addresses are unique
            memberNetCfgParams = memberVrfEntry[netId]["nwTemplateParams"]
            memberV4GwIP = memberNetCfgParams.get("gatewayIpAddress", "")
            memberV6GwIP = memberNetCfgParams.get("gatewayIpV6Address", "")

            if ((memberV4GwIP == "") and (memberV6GwIP == "")):
                # not likely, but, if case exists.. no further checks are needed
                continue

            for msdNetId in msdVrfEntry:
                msdNetCfgParams = msdVrfEntry[msdNetId]["nwTemplateParams"]

                msdV4GwIP = msdNetCfgParams.get("gatewayIpAddress", "")
                msdV6GwIP = msdNetCfgParams.get("gatewayIpV6Address", "")
                if ((memberV4GwIP != "") and (msdV4GwIP != "")):
                    if memberV4GwIP == msdV4GwIP:
                        # error - found an non unique V4 GW IP
                        hasError = True
                        respObj.setFailureRetCode()
                        respObj.addErrorReport("GW IPV4 Uniqueness", 
                          "Unique IPv4 Gateway/NetMask check fails: IP [%s] in VRF [%s] Network VNI [%d] of Fabric [%s] overlaps "
                          "with Network VNI [%d] in Fabric [%s]" % (memberV4GwIP, vrfName, netId, memberFabName, msdNetId, msdfab))

                if ((memberV6GwIP != "") and (msdV6GwIP != "")):
                    if memberV6GwIP == msdV6GwIP:
                        # error - found an non unique V6 GW IP
                        hasError = True
                        respObj.setFailureRetCode()
                        respObj.addErrorReport("GW IPV6 Uniqueness",
                          "Unique IPv6 Gateway/NetMask check fails: IP [%s] in VRF [%s] Network VNI [%d] of Fabric [%s] overlaps "
                          "with Network VNI [%d] in Fabric [%s]" % (memberV6GwIP, vrfName, netId, memberFabName, msdNetId, msdfab))

    Wrapper.print("%s: hasError [%r]" % (funcName, hasError));
    return hasError

def nwCompare(fabric1Name, fabric2Name, respObj, mfdWrapper):
    funcName = sys._getframe(0).f_code.co_name

    Wrapper.print("%s: fabric1Name [%s] fabric2Name [%s]" % (funcName, fabric1Name, fabric2Name))

    nwCheckPassed = False
    status = True
    count = 0
    #Getting the NW list of the
    try:
        #get count of nw in fabric 1
        mfdResp = mfdWrapper.getNwCount(fabric1Name)
        if mfdResp.isRetCodeSuccess():
            fabric1Len = mfdResp.getCount()
            Wrapper.print("Number of NW's Fabric 1 [%s] = %d" % (fabric1Name, fabric1Len))
            if fabric1Len == 0:
                return True, True
        else:
            Wrapper.print("Got Error, Getting Count Fabric: %s" % fabric1Name)
            respObj.addErrorReport(funcName, "Error getting NW count for fabric: " + fabric1Name)
            return False, False

        mfdResp = mfdWrapper.getNwCount(fabric2Name)
        if mfdResp.isRetCodeSuccess():
            fabric2Len = mfdResp.getCount()
            Wrapper.print("Number of NW's Fabric 2 [%s] = %d" % (fabric2Name, fabric2Len))
            if fabric2Len == 0:
              return True, True
        else:
            Wrapper.print("Got Error, Getting NW Count: %s" % fabric2Name)
            respObj.addErrorReport(funcName, "Error getting NW count for fabric: " + fabric2Name)
            return False, False

        mfdResp = mfdWrapper.getNwList(fabric1Name)
        #nw list is an array of dictionary objects
        if mfdResp.isRetCodeSuccess():
            fabric1NwList = mfdResp.getRespList()

            #get Fabric 2 NW List
            mfdResp = mfdWrapper.getNwList(fabric2Name)
            if mfdResp.isRetCodeSuccess():
                fabric2NwList = mfdResp.getRespList()
                #lets pick the one with smaller length as primary to check against
                if fabric1Len < fabric2Len:
                    baseFabricName = fabric1Name
                    base_fabric  = fabric1NwList
                    otherFabricName = fabric2Name
                    other_fabric_list = fabric2NwList
                else:
                    baseFabricName = fabric2Name
                    base_fabric = fabric2NwList
                    otherFabricName = fabric1Name
                    other_fabric_list = fabric1NwList

                Wrapper.print("%s: Base Fabric [%s] Other Fabric [%s]" % (funcName, baseFabricName, otherFabricName))
                #go through each NW and Compare if matching NW is found
                for nw in base_fabric:
                    count = 0
                    Wrapper.print("Fabric [%s] - Calling get nwId : %s" % (otherFabricName, nw["nwId"]))
                    mfdResp = mfdWrapper.getNwById(otherFabricName, int(nw["nwId"]))
                    Wrapper.print("After Calling get nwId : %s. Success [%r]" % (nw["nwId"], mfdResp.isRetCodeSuccess()))

                    if mfdResp.isRetCodeSuccess():
                        #compare every field
                        nw2 = mfdResp.getOneEntry()
                        if nw != nw2:
                            Wrapper.print("DICTIONARY MIS MATCH")
                            errList, checkPassed = nwCompareFields(nw, nw2, baseFabricName, otherFabricName)
                            if checkPassed == False:
                                count = count + 1
                                msg = ("Network VNI [%s] parameter mismatch(es) between fabric [%s] and fabric [%s]:%s%s" % (nw["nwId"],
                                      baseFabricName, otherFabricName, Util.newLine(), Util.newLine().join(errList)))
                                respObj.setFailureRetCode()
                                respObj.addErrorReport(funcName, msg)
                    elif mfdResp.isRetCodeNotFound():
                        Wrapper.print("NW ID: %s not found" % nw["nwId"])
                        #look by name as an error check to see if there a duplicate name
                        duplicateNameCheck = nwCompareName(nw, other_fabric_list, fabric1Name, fabric2Name,respObj)
                        if duplicateNameCheck == False:
                            count = count + 1
                    else:
                        Wrapper.print("NW ID: Get Error, Log it: %s" % nw["nwName"])
                        count = count + 1
                        respObj.setFailureRetCode()
                        respObj.addErrorReport(funcName, "Error getting For NW ID: " + str(nw["nwId"]))

                    Wrapper.print("%s: count = %d" % (funcName, count));
                    if count:
                        Wrapper.print("NW check Failed for NW ID: %s number of difference: %d" %(nw["nwId"], count));
                        status = False

                if status:
                    nwCheckPassed = True
                    if checkGwIPUniqueness(fabric2Name, fabric2NwList, fabric1Name, fabric1NwList, respObj):
                        nwCheckPassed = False
                        status = False
            else:
                Wrapper.print("Got Error, Getting NW List Fabric: %s" % fabric2Name)
                respObj.addErrorReport(funcName, "Error getting For NW List fabric: " + fabric2Name)
                status = False
        else:
            Wrapper.print("Got Error getting nw list: fabric: %s" % fabric1Name)
            respObj.addErrorReport(funcName, "Error getting For NW List fabric: " + fabric1Name)
            status = False
    except Exception as e:
        respObj.addErrorReport(funcName,"Exception in: NW compare. Exception: " + repr(e))
        Wrapper.print("Exception in NW compare [%s] Additional Info [%s]" % (repr(e), traceback.format_exc()));
        status = False

    return status, nwCheckPassed

def vrfCompareFields(vrf1, vrf2, fabric1, fabric2):
    funcName = sys._getframe(0).f_code.co_name
    Wrapper.print("%s: vrf1 [%s] vrf2 [%s]" % (funcName, vrf1, vrf2))

    errList = []
    try:
        params = {
                  "vrfName" : "VRF Name",
                  "vrfTemplate" : "VRF Template",
                  "vrfExtensionTemplate": "VRF Extension Template"
                 }

        for param in params:
            val1 = vrf1.get(param, None)
            val2 = vrf2.get(param, None)

            if val1 == None:
                errList.append("%s is not present in VRF entry for fabric [%s]" % (params[param], fabric1))
            elif val2 == None:
                errList.append("%s is not present in VRF entry for fabric [%s]" % (params[param], fabric2))
            elif val1 != val2:
                errList.append("%s mismatch - [%s], [%s]" % (params[param], val1, val2))

        params = {
                  #"vrfVlanId": "VRF Vlan Id",
                  "vrfDescription" : "VRF Description",
                  "maxBgpPaths" : "Max BGP Paths",
                  "maxIbgpPaths" : "Max iBGP Paths",
                  "ipv6LinkLocalFlag" : "IPv6 Link Local Flag",
                  "mtu" : "VRF Inft MTU",
                  "vrfRouteMap" : "VRF Route Map Name",
                  "vrfVlanName" : "VRF VLAN Name",
                  "tag" : "Loopback Routing Tag",
                  "vrfIntfDescription" : "VRF Interface Description"
                 }

        for param in params:
            val1 = vrf1['vrfTemplateParams'].get(param, None)
            val2 = vrf2['vrfTemplateParams'].get(param, None)

            if val1 != None and val2 != None and val1 != val2:
                errList.append("%s mismatch - [%s], [%s]. " % (params[param], val1, val2))

        # check new fields which might not be present from upgrade
        params = {
                  "disableRtAuto": "Disable RT Auto",
                  "routeTargetImport": "Route Target Import",
                  "routeTargetExport": "Route Target Export",
                  "routeTargetImportEvpn": "Route Target Import EVPN",
                  "routeTargetExportEvpn": "Route Target Export EVPN"
                 }

        params_default = {
                  "disableRtAuto": "false",
                  "routeTargetImport": "",
                  "routeTargetExport": "",
                  "routeTargetImportEvpn": "",
                  "routeTargetExportEvpn": ""
                 }

        for param in params:
            val1 = vrf1['vrfTemplateParams'].get(param, params_default[param])
            val2 = vrf2['vrfTemplateParams'].get(param, params_default[param])

            # in case user created vrf with empty value for disableRtAuto
            if param == "disableRtAuto":
                if val1 == "":
                    val1 = "false"
                if val2 == "":
                    val2 = "false"

            if val1 != val2:
                errList.append("%s mismatch - [%s], [%s]. " % (params[param], val1, val2))

    except Exception as e:
        msg = ("%s: Exception %s" % (funcName, repr(e)))
        Wrapper.print(msg)
        errList.append(msg)
    finally:
        status = True
        if len(errList):
          status = False
        Wrapper.print("%s: Status = [%r] VRF Match Error Count [%d]" % (funcName, status, len(errList)))
        return errList, status

def vrfCompare(fabric1Name, fabric2Name, respObj, mfdWrapper):
    funcName = sys._getframe(0).f_code.co_name
    #Get VRF count before getting list
    #Getting the VRF list of the
    status = True
    vrfCheckPassed = False
    count = 0
    try:
        #get count of nw in fabric 1
        mfdResp = mfdWrapper.getVRFCount(fabric1Name)
        if mfdResp.isRetCodeSuccess():
            fabric1Len = mfdResp.getCount()
            Wrapper.print("Number of VRF's Fabric 1 = %d" % fabric1Len)
            if fabric1Len == 0:
                return True, True
        else:
            Wrapper.print("Got Error, Getting VRF Count Fabric: %s" % fabric1Name)
            respObj.addErrorReport(funcName, "Error getting VRF count for fabric: " + fabric1Name)
            return False, False

        mfdResp = mfdWrapper.getVRFCount(fabric2Name)
        if mfdResp.isRetCodeSuccess():
            fabric2Len = mfdResp.getCount()
            Wrapper.print("Number of VRF's Fabric 2 = %d" % fabric2Len)
            if fabric2Len == 0:
                return True, True
        else:
            Wrapper.print("Got Error, Getting VRF Count: %s" % fabric2Name)
            respObj.addErrorReport(funcName, "Error getting VRF count for fabric: " + fabric2Name)
            return False, False

        mfdObj = mfdWrapper.getVrfList(fabric1Name)
        #vrf list is an array of dictionary objects
        if mfdObj.isRetCodeSuccess():
            fabric1VrfList = mfdObj.getRespList()
            #get Fabric 2 VRF List
            mfdObj = mfdWrapper.getVrfList(fabric2Name)
            if mfdObj.isRetCodeSuccess():
                fabric2VrfList = mfdObj.getRespList()

                #lets pick the one with smaller length as primary to check against
                if fabric1Len < fabric2Len:
                    baseFabricName = fabric1Name
                    base_fabric       = fabric1VrfList
                    otherFabricName      = fabric2Name
                    other_fabric_list = fabric2VrfList
                else:
                    baseFabricName = fabric2Name
                    base_fabric  = fabric2VrfList
                    otherFabricName = fabric1Name
                    other_fabric_list = fabric1VrfList

                #go through each VRF and Compare if matching VRF is found
                for vrf1 in base_fabric:
                    Wrapper.print("Calling get vrfId : %s" % vrf1["vrfId"])
                    mfdObj = mfdWrapper.getVrfFromId(otherFabricName, int(vrf1["vrfId"]))
                    if mfdObj.isRetCodeSuccess():
                        #compare every field
                        vrf2 = mfdObj.getOneEntry()
                        vrfFieldsErrList, checkPassed = vrfCompareFields(vrf1, vrf2, baseFabricName, otherFabricName)
                        if len(vrfFieldsErrList):
                            msg = ("VRF VNI [%s] parameter mismatch(es) between fabric [%s] and fabric [%s].%s%s" % (vrf1["vrfId"],
                              baseFabricName, otherFabricName, Util.newLine(), Util.newLine().join(vrfFieldsErrList)))
                            respObj.setFailureRetCode()
                            respObj.addErrorReport(funcName, msg)
                            count = count + 1
                    elif mfdObj.isRetCodeNotFound():
                        Wrapper.print("VRF ID: %s not found" % str(vrf1["vrfId"]))
                        #look for duplicate vrf name with different address
                        duplicateNameCheck = vrfCompareName(vrf1, other_fabric_list, 
                                                                  baseFabricName, otherFabricName,respObj)
                        if duplicateNameCheck == False:
                            count = count + 1
                            Wrapper.print("Duplicate name check failed for Vrf")
                    else:
                        Wrapper.print("VRF ID: Get Error, Fabric " + otherFabricName +  " vrfId: " +  str(vrf1["vrfId"]))
                        respObj.setFailureRetCode()
                        respObj.addErrorReport(funcName, "Got Error, Getting VRF by ID Fabric: " + 
                                               otherFabricName + " VRF ID: " + str(vrf1["vrfId"]))
                        status = False

                #if count is zero then we have a match
                if count == 0:
                    Wrapper.print("VRF check Passed");
                    vrfCheckPassed = True
            else:
                respObj.addErrorReport(funcName,"Got Error, Getting VRF List Fabric: " + fabric2Name)
                respObj.setFailureRetCode()
                Wrapper.print("Got Error, Getting VRF List Fabric: %s" % fabric2Name)
                status = False
        else:
            respObj.addErrorReport(funcName,"Got Error, Getting VRF List Fabric: " + fabric1Name)
            respObj.setFailureRetCode()
            Wrapper.print("Got Error getting vrf list: fabric: %s" % fabric2Name)
            status = False
    except Exception as e:
        respObj.addErrorReport(funcName,"Exception in: VRF compare: " + fabric1Name + " Exception " + repr(e))
        respObj.setFailureRetCode()
        Wrapper.print("Exception in VRF CHeck");
        status = False

    return status, vrfCheckPassed

