def compareParamValue(param, nw, nw2, nwId, paramNames, errList):
    paramVal1 = nw.get(param, None)
    paramVal2 = nw2.get(param, None)

    if paramVal1 != None and paramVal2 != None and paramVal1 != paramVal2:
        Wrapper.print("Checking NW ID: [%d] : Param [%s]: [%s] != [%s]" % (nwId, param, paramVal1, paramVal2))
        paramDesc = paramNames[param]
        errList.append("%s mismatch [%s], [%s]" % (paramDesc, paramVal1, paramVal2))

# This function is shared by all network types (PVLAN and non PVLAN Networks), under the assumption
# that in PVLAN Secondary Network, parameters not applicable (like mtu) are not present
def compareTemplateConfig(nw, nw2, nwId, fabric1, fabric2):
   funcName = sys._getframe(0).f_code.co_name

   errList = []
   Wrapper.print("%s: NW ID: [%d] fabric1 [%s] fabric2 [%s]" % (funcName, nwId, fabric1, fabric2))
   Wrapper.print("%s: Nw1: %s" % (funcName, nw))
   Wrapper.print("%s: Nw2: %s" % (funcName, nw2))
   try:
      paramNames = {"isLayer2Only" : "Layer 2 Only"}
      for param in paramNames:
          compareParamValue(param, nw, nw2, nwId, paramNames, errList)

      if len(errList) == 0:
          # Not comparing mcast subnet as its fabric instance
          #not comparing vlan as thats of local significance
          l3ParamNames = {"gatewayIpAddress" : "IPv4 Gateway/NetMask",
                        "gatewayIpV6Address" : "IPv6 Gateway/Prefix",
                        "mtu" : "MTU for L3 interface",
                        "suppressArp" : "ARP Suppression",
                        "secondaryGW1" : "IPv4 Secondary GW1",
                        "secondaryGW2" : "IPv4 Secondary GW2",
                        "secondaryGW3" : "IPv4 Secondary GW3",
                        "secondaryGW4" : "IPv4 Secondary GW4",
                        "vlanName" : "VLAN Name",
                        "rtBothAuto" : "L2 VNI Route-Target Both Enable",
                        "intfDescription" : "Interface Description",
                        "tag": "Routing Tag"
                        }
          for param in l3ParamNames:
            compareParamValue(param, nw, nw2, nwId, l3ParamNames, errList)

   except Exception as e:
      msg = ("%s: Exception %s" % (funcName, repr(e)))
      Wrapper.print(msg)
      errList.append(msg)
   finally:
      status = True
      if len(errList):
         status = False
      Wrapper.print("%s: Status = [%r] NW Template Config Error Count [%d]" % (funcName, status, len(errList)))
      return errList, status

