def preUpgrade(dictionaryObj):
    funcName = sys._getframe(0).f_code.co_name

    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()
    upgFromVer = dictionaryObj.get("UPGRADE_FROM", "")
    # Note: the backend will provide UPGRADE_FROM = "" if the from and to versions are the same
    isUpgrade = (upgFromVer != "")

    Wrapper.print("==========%s: Start - Fabric [%s] upgFromVer [%s] isUpgrade [%r]" % (funcName,
                                                    FABRIC_NAME, upgFromVer, isUpgrade))

    try:
        # get the current fabric settings
        fabricSettings = Util.exe(FabricWrapper.get(FABRIC_NAME)).getNvPairs()

        # set/update the fabric settings
        isSettingChange = False
        settingsToDelete = None

        if isUpgrade:
            if upgFromVer in ["11.5.4"]:
                # clear the scheduled fabric backups in settings. Customers must reenable them
                isSettingChange = setFabricSettingValue(fabricSettings, "enableScheduledBackup", "false")
                isSettingChange = setFabricSettingValue(fabricSettings, "scheduledTime", "")

        if "ENABLE_PVLAN" not in fabricSettings:
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_PVLAN", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_PVLAN_PREV", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "default_pvlan_sec_network", "")

        if "ENABLE_RS_REDIST_DIRECT" not in fabricSettings:
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_RS_REDIST_DIRECT", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "RS_ROUTING_TAG", "")
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_BGP_SEND_COMM", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_BGP_LOG_NEIGHBOR_CHANGE", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "ENABLE_BGP_BFD", "false")
            isSettingChange = setFabricSettingValue(fabricSettings, "BGW_ROUTING_TAG", "54321")
            isSettingChange = setFabricSettingValue(fabricSettings, "BGW_ROUTING_TAG_PREV", "54321")

        if isSettingChange:
            # we made some changes.. update the fabric settings with the new values
            Util.processRespObj(respObj, FabricWrapper.update(FABRIC_NAME, fabricSettings, settingsToDelete))

        if fabricSettings["CLOUDSEC_AUTOCONFIG"].lower() == "true":
            warningMsg = ("Fabric %s has CloudSec enabled, please perform Recalculate Config to initiate the CloudSec Operational View"
                           % FABRIC_NAME)
            Wrapper.print("==========preUpgrade: %s" % warningMsg)
            respObj.addWarnReport("preUpgrade", warningMsg)
            respObj.setWarningRetCode()

        if (isUpgrade and (upgFromVer in ["11.5.4", "12.1.1e"])):
           mfdResp = MfdWrapper.getMfdFabricList(FABRIC_NAME)
           if mfdResp.isRetCodeSuccess():
               fabricList = mfdResp.getFabricNameList()
               for fabric in fabricList:
                   fabricType = Util.exe(Helper.getFabricType(fabric))
                   topoObj = TopologyData(Util.exe(TopologyWrapper.get(fabric)))
                   devices = topoObj.getDevices()

                   if fabricType == "External":
                       for deviceSn in devices:
                           srchOpt = CtrlPolicySearch()
                           srchOpt.setSerialNumber(deviceSn)
                           srchOpt.setTemplateName("ext_multisite_rs_base_setup")
                           ptiList = Util.exe(PTIWrapper.getPTIs(srchOpt))
                           for pti in ptiList:
                               nvPairs = pti.getNvPairs()
                               if "BGP_MULTIHOP" not in nvPairs:
                                   nvPairs["BGP_MULTIHOP"] = "5"
                                   Util.exe(PTIWrapper.updateInstance(pti.getPolicyId(), nvPairs))
                   else:
                       for deviceSn in devices:
                           srchOpt = CtrlPolicySearch()
                           srchOpt.setSerialNumber(deviceSn)
                           srchOpt.setTemplateName("ext_multisite_overlay_setup_11_1")
                           ptiList = Util.exe(PTIWrapper.getPTIs(srchOpt))
                           for pti in ptiList:
                               nvPairs = pti.getNvPairs()
                               updatePti = False
                               if "BGP_MULTIHOP" not in nvPairs:
                                   nvPairs["BGP_MULTIHOP"] = "5"
                                   updatePti = True
                               if "TRM_ENABLED" not in nvPairs:
                                   nvPairs["TRM_ENABLED"] = "false"
                                   updatePti = True
                               if updatePti == True:
                                   Util.exe(PTIWrapper.updateInstance(pti.getPolicyId(), nvPairs))
    except Exception as e:
        msg = "Unexpected error during upgrade processing"
        if isinstance(e, respObjError):
            processUpgradeRespObjWithMsg(FABRIC_NAME + ":UPGRADE", msg, respObj, e.value)
        else:
            Util.handleException(msg, e, respObj)
    finally:
        Wrapper.print("==========%s: End - Fabric [%s] Success = [%r]" % (funcName, FABRIC_NAME, respObj.isRetCodeSuccess()))
        return respObj

def processUpgradeRespObjWithMsg(entity, message, respObj, newResp):
    respObj.addErrorReport(entity, message)
    respObj.setFailureRetCode()
    Util.processRespObj(respObj, newResp)

def cloudSecSanityCheck(respObj, fabricInit):
    if CLOUDSEC_AUTOCONFIG == "false":
        return True

    if CLOUDSEC_ALGORITHM == "AES_128_CMAC" and len(CLOUDSEC_KEY_STRING) != 66:
        errorMsg = "CloudSec key string length must be 66 with AES_128_CMAC."
        Wrapper.print("cloudSecSanityCheck: %s %s" % (FABRIC_NAME, errorMsg))
        respObj.addErrorReport("cloudSecSanityCheck", errorMsg)
        respObj.setFailureRetCode()
        return False
    elif CLOUDSEC_ALGORITHM == "AES_256_CMAC" and len(CLOUDSEC_KEY_STRING) != 130:
        errorMsg = "CloudSec key string length must be 130 with AES_256_CMAC."
        Wrapper.print("cloudSecSanityCheck %s %s" % (FABRIC_NAME, errorMsg))
        respObj.addErrorReport("cloudSecSanityCheck", errorMsg)
        respObj.setFailureRetCode()
        return False

    # check whether there is any border gateway that does not support Cloudsec
    mfdResp = MfdWrapper.getMfdFabricList(FABRIC_NAME)
    if not mfdResp.isRetCodeSuccess():
        respObj.addErrorReport("cloudSecSanityCheck", "Failed to get Fabric List for %s "% (FABRIC_NAME))
        respObj.setFailureRetCode()
        return False

    fabricList = mfdResp.getFabricNameList()
    if len(fabricList) == 0:
        return True

    CloudSecNodes, NonCloudSecNodes = [],[]
    for i in range (0, len(fabricList)):
        fabricType = Util.exe(Helper.getFabricType(fabricList[i]))
        if fabricType != "Switch_Fabric":
            continue

        topoObj = TopologyData(Util.exe(TopologyWrapper.get(fabricList[i])))
        bgwNodes = getBorderGateways(topoObj)
        for bgwNode in bgwNodes:
            isSupported, reason = Util.isCloudSecSupported(topoObj, bgwNode)
            if isSupported:
                CloudSecNodes.append({"SN":bgwNode, "FABRIC_NAME":fabricList[i]})
            else:
                NonCloudSecNodes.append({"SN":bgwNode, "REASON":reason, "FABRIC_NAME":fabricList[i], "TOPO":topoObj})

    Wrapper.print("cloudSecSanityCheck: CloudSec capable nodes: %s. CloudSec incapable nodes: %s" % (CloudSecNodes, NonCloudSecNodes))

    if NonCloudSecNodes:
        if CLOUDSEC_ENFORCEMENT == "strict":
            errorMsg = "CloudSec cannot be in strict mode when there are border gateways that do not support CloudSec: "
            for node in NonCloudSecNodes:
                hostName = node["TOPO"].get(TopologyInfoType.HOSTNAME, node["SN"])
                errorMsg += Util.newLine() + "%s/%s: %s" % (hostName, node["SN"], node["REASON"])
            Wrapper.print("cloudSecSanityCheck: %s" % errorMsg)
            respObj.addErrorReport("cloudSecSanityCheck", errorMsg)
            respObj.setFailureRetCode()
            return False
        elif fabricInit:
            warningMsg = ""
            for node in NonCloudSecNodes:
                hostName = node["TOPO"].get(TopologyInfoType.HOSTNAME, node["SN"])
                warningMsg += Util.newLine() + "%s/%s: %s" % (hostName, node["SN"], node["REASON"])
            if warningMsg != "":
                warningMsg = "CloudSec will not be enabled on the following gateway device(s):" + warningMsg
                Wrapper.print("cloudSecSanityCheck: %s" % warningMsg)
                respObj.addWarnReport("cloudSecSanityCheck", warningMsg)
                respObj.setWarningRetCode()

    # check whether TRM is enabled on any overlay IFC
    for node in CloudSecNodes:
        srchOpt = CtrlPolicySearch()
        srchOpt.setSerialNumber(node["SN"])
        srchOpt.setTemplateName("ext_multisite_overlay_setup_11_1")
        overlayPtiList = Util.exe(PTIWrapper.getPTIs(srchOpt))
        for pti in overlayPtiList:
            if pti.getNvPairs()["TRM_ENABLED"] == "true":
                errorMsg = "CloudSec and Multisite TRM can not co-exist. TRM is enabled on Multisite Overlay IFC."
                Wrapper.print("cloudSecSanityCheck: %s" % errorMsg)
                respObj.addErrorReport("cloudSecSanityCheck", errorMsg)
                respObj.setFailureRetCode()
                return False

    return True

def loopbackIdSanityCheck(respObj):
    funcName = sys._getframe(0).f_code.co_name

    mfdResp = MfdWrapper.getMfdFabricList(FABRIC_NAME)
    if not mfdResp.isRetCodeSuccess():
        respObj.addErrorReport(funcName, "Failed to get Fabric List for %s "% (FABRIC_NAME))
        respObj.setFailureRetCode()
        return False

    fabricList = mfdResp.getFabricNameList()
    if len(fabricList) == 0:
        return True

    for i in range (0, len(fabricList)):
        fabricSettings = Util.exe(FabricWrapper.get(fabricList[i])).getNvPairs()
        bgpLoopbackId = fabricSettings.get("BGP_LB_ID", "")
        nveLoopbackId = fabricSettings.get("NVE_LB_ID", "")

        if MS_LOOPBACK_ID == bgpLoopbackId or MS_LOOPBACK_ID == nveLoopbackId:
            errorMsg = ("Cannot change 'Multi-Site VTEP VIP Loopback Id' to %s since "
                "it conflicts with '%s Loopback Id' in member fabric [%s]"
                % (MS_LOOPBACK_ID, "Routing" if MS_LOOPBACK_ID==bgpLoopbackId else "NVE", fabricList[i]))
            respObj.addErrorReport(funcName, errorMsg)
            respObj.setFailureRetCode()
            return False

    return True

def fabricInit(dictonaryObj):
    funcName = sys._getframe(0).f_code.co_name
    Wrapper.print("==========ACTION: FAB [%s]: Start: %s" % (FABRIC_NAME, funcName))
    respObj = WrappersResp.getRespObj()
    respObj.setSuccessRetCode()

    try:
       Util.exe(actionAllow())

       Wrapper.print("%s: RP_SERVER_IP [%s]" % (funcName, RP_SERVER_IP))
       #validate router server list if any
       if RP_SERVER_IP != "":
          rmSpace = RP_SERVER_IP.replace(" ", "")
          rpList = rmSpace.split(",")
          rmSpace = BGP_RP_ASN.replace(" ", "")
          asnList = rmSpace.split(",")
          if len (rpList) != len (asnList):
             respObj.addErrorReport("msdFabricInit", "Number of Router Servers and BGP ASN must match")
             respObj.setFailureRetCode()
             return respObj
          #validate that all ASN's are valid
          for asn in asnList:
             respObj = Helper.isValidAsn (asn)
             if respObj.isRetCodeFailure():
                return respObj

       if not isFabricMSOSiteGroup(FABRIC_NAME):
           Wrapper.print("Setting up L3_PARTITION_ID_RANGE")
           Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "L3_VNI", L3_PARTITION_ID_RANGE))
           Wrapper.print("Setting up L2_SEGMENT_ID_RANGE")
           Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "L2_VNI", L2_SEGMENT_ID_RANGE))
           Wrapper.print("Setting up MS LOOPBACK ID POOL")
           Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "LOOPBACK100_IP_POOL", PoolType.IP, LOOPBACK100_IP_RANGE))

       Util.exe(RM.addOrUpdatePoolData(FABRIC_NAME, "MS DCI IP Pool", PoolType.SUBNET, DCI_SUBNET_RANGE, DCI_SUBNET_TARGET_MASK))

       if not cloudSecSanityCheck(respObj, True):
            return respObj

       if not loopbackIdSanityCheck(respObj):
            return respObj

       dict = getGlobals()
       Util.processRespObj(respObj, PTI.executePyTemplateMethod("fabric_utility_11_1", dict, "validatePvlanFabSettings"))
       if respObj.isRetCodeFailure():
            return respObj

       if ENABLE_PVLAN_PREV != ENABLE_PVLAN:
            Util.exe(FabricWrapper.update(FABRIC_NAME, "ENABLE_PVLAN_PREV", ENABLE_PVLAN))

            # ENABLE_PVLAN value is passed from MSD to applicable child fabrics
            mfdResp = MfdWrapper.getMfdFabricList(FABRIC_NAME)
            if mfdResp.isRetCodeSuccess():
                fabricList = mfdResp.getFabricNameList()
                for fabricName in fabricList:
                    mFabricSettings = Util.exe(FabricWrapper.get(fabricName)).getNvPairs()
                    if "ENABLE_PVLAN" in mFabricSettings:
                        mFabricSettings["ENABLE_PVLAN"] = ENABLE_PVLAN
                        mFabricSettings["ENABLE_PVLAN_PREV"] = ENABLE_PVLAN
                        mFabricSettings["default_pvlan_sec_network"] = default_pvlan_sec_network
                        FabricWrapper.update(fabricName, mFabricSettings)

       Util.exe(BRW.CreateBackUpJob(FABRIC_NAME, "false", enableScheduledBackup, scheduledTime))
    except Exception as e:
        if isinstance(e, respObjError):
            Util.processRespObj(respObj, e.value)
        else:
            Util.handleException("Unexpected error creating fabric", e, respObj)
    finally:
        Wrapper.print("==========ACTION: FAB [%s]: Finish: %s: Success = [%r]" %
                (FABRIC_NAME, funcName, respObj.isRetCodeSuccess()))
