def preAdd(dictionaryObj):
    funcName = sys._getframe(0).f_code.co_name
    Wrapper.print("==========ACTION: FAB [%s]: Start: preAdd:" % (FABRIC_NAME))
    try:
       Util.exe(actionAllow())
    except respObjError as e:
       return e.value
    vrfCheckPassed = False
    nwCheckPassed  = False
    count = 0
    respObj = WrappersResp.getRespObj()
    mfdWrapper = MfdWrapper.getMfdWrapper()

    Wrapper.print("Fabric [%s] dictionary [%d][%s]" % (FABRIC_NAME, len(dictionaryObj), str(dictionaryObj)))

    #check if we are called only to log an error
    if (dictionaryObj.containsKey("errorDetected")):
       respObj.addErrorReport(preAdd.__name__, dictionaryObj["errorDetected"])
       respObj.setFailureRetCode()
       return respObj

    Wrapper.print("Fabric 1 [%s], Fabric 2 [%s] Type/Tech [%s]/[%s]" % (dictionaryObj["fabric1Name"], 
      dictionaryObj["fabric2Name"], dictionaryObj["fabricType"], dictionaryObj["fabricTechnology"]))

    #for now allow all external fabrics to be added
    if dictionaryObj["fabricType"] == "External":
       Wrapper.print("Fabric 2 Type = is external, pass it")
       respObj.setSuccessRetCode()
       return respObj

    #for now treat ebgp routed fabric as external, all external fabrics to be added
    if dictionaryObj["fabricTechnology"] == "eBGP_Routed_Fabric" or dictionaryObj["fabricTechnology"] == "EBGPVXLANFabric":
       Wrapper.print("Fabric 2 Type = is: %s, pass it" %dictionaryObj["fabricTechnology"])
       respObj.setSuccessRetCode()
       return respObj

    #for now allow enhanced classic fabric to be added
    if dictionaryObj["fabricTechnology"] == "VLANFabric":
       Wrapper.print("Fabric 2 Type = is: %s, pass it" %dictionaryObj["fabricTechnology"])
       respObj.setSuccessRetCode()
       return respObj

    if "IOS-XE" in dictionaryObj["fabricTechnology"] and ENABLE_PVLAN == "true":
        errMsg = "Campus VXLAN EVPN fabric does not support Private VLAN. It cannot be added into %s which has Private VLAN enabled. " % FABRIC_NAME
        Wrapper.print("%s: %s" % (funcName, errMsg))
        respObj.addErrorReport(preAdd.__name__, errMsg)
        respObj.setFailureRetCode()
        return respObj

    f1 = dictionaryObj["fabric1Name"]
    f2 = dictionaryObj["fabric2Name"]
    f1FabricSettings = Util.exe(FabricWrapper.get(f1)).getNvPairs()
    isUnderlayV6En = f1FabricSettings.get("UNDERLAY_IS_V6", "false")
    if isUnderlayV6En != "true":
        errorMsg = Util.validateFabricSnetRange(f1, f2)
        if errorMsg:
            errorMsg = ("Fabric [%s] cannot be added to MSD fabric [%s]. " % (f1, f2)) + errorMsg + ("Please correct the IP ranges and retry.")
            respObj.addErrorReport(funcName, errorMsg)
            respObj.setFailureRetCode()
            return respObj
    else:
        errorMsg = ("Fabric [%s] with IPv6 underlay cannot be moved into MSD fabric [%s]." % (f1, f2))
        respObj.addErrorReport(funcName, errorMsg)
        respObj.setFailureRetCode()
        return respObj

    # f1 is child fabric and f2 is MSD
    f1FabricSettings = Util.exe(FabricWrapper.get(f1)).getNvPairs()
    sgt_enable = f1FabricSettings.get("ENABLE_SGT", "false")
    if sgt_enable == "true":
        errorMsg = ("Fabric [%s] with Security Groups enabled cannot be moved into MSD fabric [%s]." % (f1, f2))
        respObj.addErrorReport(funcName, errorMsg)
        respObj.setFailureRetCode()
        return respObj

    # do not allow member fabric that have conflict fabric loopback Id
    # do not allow member fabric that have switches in BF migration mode
    # warn if an Easy fabric as member fabric without any border gateway
    dictObj = {"FABRIC_NAME" : dictionaryObj["fabric1Name"], "MSD_FABRIC_NAME" : dictionaryObj["fabric2Name"]}
    Util.processRespObj(respObj, PTI.executePyTemplateMethod("fabric_upgrade_11_1", dictObj, "addFabricAsMemberEntryCheck"))
    if respObj.isRetCodeFailure():
        return respObj

    Wrapper.print("Fabric 2 gw mac= %s" % dictionaryObj["anycast_gw_mac"])
    Wrapper.print("Fabric 1 gw mac= %s" % ANYCAST_GW_MAC)


    if Util.normalizeMac(ANYCAST_GW_MAC) == Util.normalizeMac(dictionaryObj["anycast_gw_mac"]):
        Wrapper.print("ANYCAST GW MA CHECK PASSED")
    else:
	 Wrapper.print("ANYCAST GW MA CHECK FAILED")
	 respObj.addErrorReport(preAdd.__name__,
		"Anycast gateway mac mis match Fab 1: " + ANYCAST_GW_MAC + \
			 " Fab2: " + dictionaryObj["anycast_gw_mac"])
	 respObj.setFailureRetCode()
         return respObj	 


    #Perform an ASN uniqueness Check
    new_respObj = mfdWrapper.checkIfAsnIsUnique(FABRIC_NAME, dictionaryObj["fabric1Name"])
    Util.processRespObj(respObj, new_respObj)
    if respObj.isRetCodeFailure():
       Wrapper.print("Fabric ASN Uniqueness check failed = %s" % dictionaryObj["fabric2Name"])
       return respObj

    #Perform a Site ID uniqueness Check
    new_respObj = mfdWrapper.checkIfSiteIdIsUnique(FABRIC_NAME, dictionaryObj["fabric1Name"])
    Util.processRespObj(respObj, new_respObj)
    if respObj.isRetCodeFailure():
       Wrapper.print("Fabric Site-ID Uniqueness check failed = %s" % dictionaryObj["fabric2Name"])
       return respObj

    #Perform a fabric subnet uniqueness test. If warning make sure final result is warning
    new_respObj = mfdWrapper.checkIfUnderlayIPRangeIsUnique(FABRIC_NAME, dictionaryObj["fabric1Name"])
    Util.processRespObj(respObj, new_respObj)
    if respObj.isRetCodeFailure():
       Wrapper.print("Fabric IP Subnet Uniqueness check failed = %s" % dictionaryObj["fabric2Name"])
       return respObj

    if respObj.isRetCodeWarning():
       Wrapper.print("Fabric IP Subnet Uniqueness check gave warning = %s" % dictionaryObj["fabric2Name"])
       finalResult = 1
    else:
       finalResult = 0

    status, vrfCheckPassed = vrfCompare(dictionaryObj["fabric1Name"], dictionaryObj["fabric2Name"],
                                        respObj, mfdWrapper)

    if status == False:
       respObj.setFailureRetCode()
       return respObj


    status, nwCheckPassed = nwCompare(dictionaryObj["fabric1Name"], dictionaryObj["fabric2Name"],
                                      respObj, mfdWrapper)
    Wrapper.print("Status: " + str(status) + " nwCheckPassed: " + str(nwCheckPassed))

    if status == False:
       respObj.setFailureRetCode()
       return respObj


    if vrfCheckPassed == True and nwCheckPassed == True:
        respObj.setSuccessRetCode()
	if finalResult == 1:
	    respObj.setWarningRetCode()
    else:
        respObj.setFailureRetCode()

    if CLOUDSEC_AUTOCONFIG == "true" and CLOUDSEC_ENFORCEMENT == "strict":
        # check if any BGW is not CloudSec capable
        topoObj = TopologyData(Util.exe(TopologyWrapper.get(dictionaryObj["fabric1Name"])))
        bgwNodes = getBorderGateways(topoObj)
        NonCloudSecNodes = []
        for bgwNode in bgwNodes:
            isSupported, reason = Util.isCloudSecSupported(topoObj, bgwNode)
            if not isSupported:
                NonCloudSecNodes.append({"SN":bgwNode, "REASON":reason})

        if NonCloudSecNodes:
            warningMsg = "CloudSec is in strict mode while fabric %s has the following border gateway devices that do not support CloudSec: " % dictionaryObj["fabric1Name"]
            for node in NonCloudSecNodes:
                hostName = topoObj.get(TopologyInfoType.HOSTNAME, node["SN"])
                warningMsg += Util.newLine() + "%s/%s: %s" % (hostName, node["SN"], node["REASON"])
            Wrapper.print("cloudSecSanityCheck: %s" % warningMsg)
            new_RespObj = WrappersResp.getRespObj()
            new_respObj.addWarnReport("preAdd", warningMsg)
            new_respObj.setWarningRetCode()
            Util.processRespObj(respObj, new_respObj)

    if not respObj.isRetCodeFailure():
        # update the child fabric's PVLAN setting
        if ENABLE_PVLAN == "true" and "ENABLE_PVLAN" in f1FabricSettings and f1FabricSettings["ENABLE_PVLAN"] == "false":
            f1FabricSettings["ENABLE_PVLAN"] = "true"
            f1FabricSettings["ENABLE_PVLAN_PREV"] = "true"
            f1FabricSettings["default_pvlan_sec_network"] = default_pvlan_sec_network
            FabricWrapper.update(f1, f1FabricSettings)

    return respObj


