def getBorderGateways(topologyDataObj):
   Wrapper.print("getBorderGateways:")
   borderGwLeaves = topologyDataObj.get(TopologyInfoType.BORDER_GATEWAY_LEAVES)
   borderGwSpines = topologyDataObj.get(TopologyInfoType.BORDER_GATEWAY_SPINES)
   borderGwSSpines = topologyDataObj.get(TopologyInfoType.BORDER_GATEWAY_SUPER_SPINES)
   return (borderGwLeaves + borderGwSpines + borderGwSSpines)

def getSharedBorders(topologyDataObj):
    borderNodes = topologyDataObj.get(TopologyInfoType.BORDER_LEAVES)
    sharedBorderNodes = []
    for border in borderNodes:
        ptiList = Util.exe(PTI.get(border, "SWITCH", "SWITCH", "", "shared_border_state"))
        if len(ptiList) > 0:
            sharedBorderNodes.append(border)

    return sharedBorderNodes

def getGlobals(additionalDict=None):
    newDict = {}
    gDict = globals()
    for key in gDict.keys():
        if ((type(gDict[key]) is str) or 
            (type(gDict[key]) is dict)):
            newDict[key] = gDict[key]
    if additionalDict:
        newDict.update(additionalDict)
    return newDict

